import jsPDF from "jspdf";

// ============================================================================
// Grift font — base64-encoded OpenType files
// ============================================================================

const GRIFT_REGULAR_BASE64 = "";

const GRIFT_BOLD_BASE64 = "";

/**
 * Register Grift font with a jsPDF instance.
 * After calling this, the font can be used as:
 *   doc.setFont("Grift", "normal")
 *   doc.setFont("Grift", "bold")
 */
export function registerGriftFont(doc: jsPDF): void {
  // Register Regular
  doc.addFileToVFS("Grift-Regular.otf", GRIFT_REGULAR_BASE64);
  doc.addFont("Grift-Regular.otf", "Grift", "normal");

  // Register Bold
  doc.addFileToVFS("Grift-Bold.otf", GRIFT_BOLD_BASE64);
  doc.addFont("Grift-Bold.otf", "Grift", "bold");
}
